import{_ as a,a as r}from"./chunks/添加渠道.o1VHzHEI.js";import{_ as t,o,c as i,a2 as n}from"./chunks/framework.DnrXFDHb.js";const b=JSON.parse('{"title":"Añadir un canal Hugging Face","description":"","frontmatter":{},"headers":[],"relativePath":"es/upload/huggingface.md","filePath":"es/upload/huggingface.md","lastUpdated":1781962217000}'),d={name:"es/upload/huggingface.md"};function l(c,e,s,u,g,p){return o(),i("div",null,[...e[0]||(e[0]=[n('<h1 id="anadir-un-canal-hugging-face" tabindex="-1">Añadir un canal Hugging Face <a class="header-anchor" href="#anadir-un-canal-hugging-face" aria-label="Permalink to &quot;Añadir un canal Hugging Face&quot;">​</a></h1><p>El canal Hugging Face guarda archivos en un repositorio de Hugging Face.</p><h2 id="que-preparar" tabindex="-1">Qué preparar <a class="header-anchor" href="#que-preparar" aria-label="Permalink to &quot;Qué preparar&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Requisito</th><th>Uso</th></tr></thead><tbody><tr><td>Cuenta de Hugging Face</td><td>Gestionar repositorio y token</td></tr><tr><td>Repository</td><td>Lugar donde se guardan los archivos</td></tr><tr><td>Access Token</td><td>Permitir escritura desde ImgBed</td></tr><tr><td>Directorio</td><td>Opcional</td></tr></tbody></table><h2 id="crear-token" tabindex="-1">Crear Token <a class="header-anchor" href="#crear-token" aria-label="Permalink to &quot;Crear Token&quot;">​</a></h2><p>En los ajustes de Hugging Face, crea un Access Token con permiso para escribir en el repositorio.</p><p><img src="'+a+'" alt="Crear Token" loading="lazy"></p><p>Copia el token y guárdalo de forma segura.</p><h2 id="rellenar-en-imgbed" tabindex="-1">Rellenar en ImgBed <a class="header-anchor" href="#rellenar-en-imgbed" aria-label="Permalink to &quot;Rellenar en ImgBed&quot;">​</a></h2><p>En Configuración de subida, elige <code>Hugging Face</code>.</p><table tabindex="0"><thead><tr><th>Campo</th><th>Valor</th></tr></thead><tbody><tr><td>Nombre del canal</td><td>Por ejemplo <code>HF Storage</code></td></tr><tr><td>Repository</td><td><code>usuario/repositorio</code></td></tr><tr><td>Token</td><td>Hugging Face Access Token</td></tr><tr><td>Directorio</td><td>Opcional, normalmente <code>imgbed</code></td></tr><tr><td>Nota</td><td>Opcional</td></tr></tbody></table><p><img src="'+r+'" alt="Añadir canal" loading="lazy"></p><h2 id="verificacion" tabindex="-1">Verificación <a class="header-anchor" href="#verificacion" aria-label="Permalink to &quot;Verificación&quot;">​</a></h2><ol><li>Guarda el canal.</li><li>Sube una imagen de prueba.</li><li>Comprueba que el archivo aparece en el repositorio.</li><li>Abre el enlace desde ImgBed.</li></ol><h2 id="precauciones" tabindex="-1">Precauciones <a class="header-anchor" href="#precauciones" aria-label="Permalink to &quot;Precauciones&quot;">​</a></h2><ul><li>Revisa si el repositorio es público o privado. En un repositorio público, los archivos pueden quedar visibles.</li><li>Da al token solo los permisos necesarios.</li><li>Para muchos archivos o tráfico elevado, ten en cuenta las limitaciones de Hugging Face.</li></ul>',16)])])}const f=t(d,[["render",l]]);export{b as __pageData,f as default};
